const ipn = $input.first().json.body;


const productTags = {

  670519: { 
    monthly: "voll_m_001", 
    annual: "voll_j_002",
    trial: "voll_m_trial_005", 
    ezycourse_id: { monthly: 4690, annual: 4690 } 
  }
};

const tags = ipn.tags ? ipn.tags.toLowerCase().split(",") : [];

let billing_interval = "unknown";
let ezycourse_product_id;

const tagMap = productTags[ipn.product_id];

if (tagMap) {
    if (tagMap.trial && tags.includes(tagMap.trial.toLowerCase())) {
        if (Number(ipn.amount_brutto) === 0) {
            billing_interval = "monthly"; // free trial
        } else {
            billing_interval = "monthly"; // trial converted to paid
        }
        ezycourse_product_id = tagMap.ezycourse_id.monthly;
    } 
    else if (tags.includes(tagMap.monthly.toLowerCase())) {
        billing_interval = "monthly";
        ezycourse_product_id = tagMap.ezycourse_id.monthly;
    } 
    else if (tags.includes(tagMap.annual.toLowerCase())) {
        billing_interval = "annual";
        ezycourse_product_id = tagMap.ezycourse_id.annual;
    }
}

const today = new Date();
const valid_until = new Date(today);

if (tagMap?.trial && tags.includes(tagMap.trial.toLowerCase())) {
    if (Number(ipn.amount_brutto) === 0) {
        // Free trial
        valid_until.setDate(valid_until.getDate() + 14);
    } else {
        valid_until.setMonth(valid_until.getMonth() + 1);
    }
} else {
    if (billing_interval === "monthly") valid_until.setMonth(valid_until.getMonth() + 1);
    if (billing_interval === "annual") valid_until.setFullYear(valid_until.getFullYear() + 1);
}

// Format date helper
const formatDate = (d) => d.toISOString().split("T")[0];

// Build output object
const output = {
    email: ipn.email,
    first_name: ipn.first_name,
    last_name: ipn.last_name,
    order_id: ipn.order_id,
    transaction_id: ipn.transaction_id,
    product_id: ipn.product_id,
    product_name: ipn.product_name,
    amount_brutto: Number(ipn.amount_brutto),
    currency: ipn.currency,
    billing_interval,
    valid_until: formatDate(valid_until),
    next_payment_at: formatDate(valid_until),
    amount_credited: Number(ipn.amount_brutto),
    ezycourse_product_id,
    quota_reset_date: formatDate(valid_until) // reset quota for trial users
};

if (ipn.upgraded_order_id) output.upgraded_order_id = ipn.upgraded_order_id;
if (ipn.delivery_date) output.delivery_date = ipn.delivery_date;
if (ipn.upgrade_type) output.upgrade_type = ipn.upgrade_type;

if (tagMap?.trial && tags.includes(tagMap.trial.toLowerCase()) && Number(ipn.amount_brutto) === 0) {
    output.status = "trial";
} else if (ipn.delivery_date && new Date(ipn.delivery_date) > today) {
    output.status = "scheduled";
} else {
    output.status = "active";
}

return [{ json: output }];

