const PLAN_CONFIG = {
    '670519': {
        'vollmitgliedschaft,voll_m_trial_005': { name: 'Trial', tier: 1, priceLevel: 0 },
        'vollmitgliedschaft,voll_m_001': { name: 'Monthly', tier: 1, priceLevel: 1 },
        'vollmitgliedschaft,voll_j_002': { name: 'Yearly', tier: 2, priceLevel: 2 },
    },
};
let current = $input.first().json;
let incoming = $('Received IPN Event From Digistore').first().json.body;

let currentProductId = current.product_id;
let incomingProductId = incoming.product_id;

let currentPlanKey = current.payplan_id;
let incomingPlanKey = incoming.tags;

let planChange = 'unknown';
let action = 'manual review needed';

if (PLAN_CONFIG[currentProductId] && PLAN_CONFIG[incomingProductId]) {
    if (currentProductId === incomingProductId) {

        let currentPlan = PLAN_CONFIG[currentProductId][currentPlanKey];
        let incomingPlan = PLAN_CONFIG[incomingProductId][incomingPlanKey];

        if (!currentPlan || !incomingPlan) {
            planChange = 'unknown';
            action = 'manual review needed';
        } else {

            // Combine tier + priceLevel into a single comparable score
            const currentScore = currentPlan.tier * 10 + currentPlan.priceLevel;
            const incomingScore = incomingPlan.tier * 10 + incomingPlan.priceLevel;

            if (incomingScore > currentScore) {
                planChange = 'upgrade';
                action = 'change plan';
            } else if (incomingScore < currentScore) {
                planChange = 'downgrade';
                action = 'change plan';
            } else {
                planChange = 'same plan';
                action = 'renew';
            }
        }

    } else {
        // Different product
        planChange = 'change product';
        action = 'change plan';
    }
} else {
    planChange = 'unknown';
    action = 'manual review needed';
}

return {
    planChange,
    action,
    currentProductId,
    incomingProductId,
    currentPlanKey,
    incomingPlanKey
};

